-- ─────────────────────────────────────────────────────────────────────────────
-- 17. backtest_trade_position
-- ─────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS backtest_trade_position (
    trade_position_id         UUID          PRIMARY KEY,
