-- ============================================================================
-- V43__add_regime_gate_to_account_strategy.sql
-- ============================================================================
ALTER TABLE account_strategy
    ADD COLUMN IF NOT EXISTS regime_gate_enabled         BOOLEAN      NOT NULL DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS allowed_trend_regimes       VARCHAR(100)          NULL,
    ADD COLUMN IF NOT EXISTS allowed_volatility_regimes  VARCHAR(100)          NULL;

COMMENT ON COLUMN account_strategy.regime_gate_enabled IS
    'When true, live entries are gated on the current FeatureStore regime matching allowed_trend_regimes / allowed_volatility_regimes.';
COMMENT ON COLUMN account_strategy.allowed_trend_regimes IS
    'Comma-separated trend_regime values permitted for entry (e.g. BULL,NEUTRAL). NULL means any regime passes.';
COMMENT ON COLUMN account_strategy.allowed_volatility_regimes IS
    'Comma-separated volatility_regime values permitted for entry (e.g. NORMAL,LOW). NULL means any regime passes.';


-- ============================================================================
-- V44__add_concentration_limits_to_account.sql
-- ============================================================================
ALTER TABLE accounts
    ADD COLUMN IF NOT EXISTS max_corr_block_threshold       NUMERIC(5, 4) NULL,
    ADD COLUMN IF NOT EXISTS max_capital_concentration_pct  NUMERIC(5, 2) NULL;

COMMENT ON COLUMN accounts.max_corr_block_threshold IS
    'Pearson correlation threshold (0.0–1.0). When a new entry strategy has 30-day daily P&L correlation >= this value with any other same-side open strategy, the entry is blocked. NULL disables the check.';
COMMENT ON COLUMN accounts.max_capital_concentration_pct IS
    'Max sum of capital_allocation_pct allowed across same-direction open strategies. E.g. 80 blocks a new LONG when existing LONGs already occupy 75%+ of allocation. NULL disables the check.';


-- ============================================================================
-- V45__add_kelly_sizing_to_account_strategy.sql
-- ============================================================================
ALTER TABLE account_strategy
    ADD COLUMN IF NOT EXISTS kelly_sizing_enabled BOOLEAN      NOT NULL DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS kelly_max_fraction   NUMERIC(5,4) NOT NULL DEFAULT 0.2500;


-- ============================================================================
-- V46__add_account_strategy_version.sql
-- ============================================================================
-- Optimistic-locking version counter for account_strategy.
-- Prevents concurrent activation requests from both succeeding and
-- breaking the "at most one enabled preset per (account, strategy, symbol,
-- interval)" invariant. JPA @Version increments this on every UPDATE;
-- a stale-read conflict throws OptimisticLockingFailureException.
ALTER TABLE account_strategy
    ADD COLUMN version BIGINT NOT NULL DEFAULT 0;

